// App.tsx — wrap the app in CopilotKit
import { CopilotKit }     from "@copilotkit/react-core";
import { CopilotSidebar } from "@copilotkit/react-ui";
import "@copilotkit/react-ui/styles.css";
import { TaskManager }    from "./TaskManager";

export function App() {
  return (
    <CopilotKit runtimeUrl="/api/copilot">
      <CopilotSidebar
        instructions="You are a task management assistant. Help the user add, complete, and organise tasks."
        labels={{ title: "Task Copilot", initial: "How can I help you with your tasks today?" }}
        defaultOpen={false}
      >
        <TaskManager />
      </CopilotSidebar>
    </CopilotKit>
  );
}

// TaskManager.tsx — share task list state with the copilot
import { useCopilotReadable } from "@copilotkit/react-core";
import { useState }           from "react";

interface Task { id: string; title: string; done: boolean; priority: "low"|"medium"|"high"; }

export function TaskManager() {
  const [tasks, setTasks] = useState<Task[]>([]);

  // The copilot reads this on every render — no extra API call needed
  useCopilotReadable({
    description: "The user's current task list",
    value: tasks,
  });

  // Also expose completion percentage so the model can reference it
  useCopilotReadable({
    description: "Task completion statistics",
    value: {
      total:     tasks.length,
      completed: tasks.filter(t => t.done).length,
      pct:       tasks.length ? Math.round(tasks.filter(t => t.done).length / tasks.length * 100) : 0,
    },
  });

  return (
    <ul className="space-y-2">
      {tasks.map(task => (
        <li key={task.id} className="flex items-center gap-2 p-3 rounded-lg bg-slate-800">
          <input type="checkbox" checked={task.done}
                 onChange={() => setTasks(ts => ts.map(t => t.id === task.id ? {...t, done: !t.done} : t))} />
          <span className={task.done ? "line-through text-slate-500" : "text-slate-200"}>{task.title}</span>
          <span className={`ml-auto text-xs px-2 py-0.5 rounded-full ${
            task.priority === "high"   ? "bg-red-900 text-red-300"    :
            task.priority === "medium" ? "bg-amber-900 text-amber-300" : "bg-slate-700 text-slate-400"
          }`}>{task.priority}</span>
        </li>
      ))}
    </ul>
  );
}

// In TaskManager, register actions the copilot can invoke
import { useCopilotAction } from "@copilotkit/react-core";
import { v4 as uuid }       from "uuid";

// Inside TaskManager component body:

useCopilotAction({
  name: "addTask",
  description: "Add a new task to the user's task list",
  parameters: [
    { name: "title",    type: "string",  description: "Task title",    required: true  },
    { name: "priority", type: "string",  description: "low | medium | high", required: false },
  ],
  // Optional render prop: show a custom UI card while the action runs
  render: ({ status, args }) => (
    <div className="my-1 flex items-center gap-2 rounded-lg border border-slate-700 p-3 text-sm">
      <span className={status === "inProgress" ? "animate-pulse text-indigo-400" : "text-green-400"}>
        {status === "inProgress" ? "Adding task..." : "Task added"}
      </span>
      {args.title && <span className="text-slate-300">{args.title}</span>}
    </div>
  ),
  handler: async ({ title, priority = "medium" }) => {
    setTasks(ts => [...ts, { id: uuid(), title, done: false, priority: priority as Task["priority"] }]);
    return `Added task: "${title}" with ${priority} priority`;
  },
});

useCopilotAction({
  name: "completeTask",
  description: "Mark a task as complete by its title (case-insensitive match)",
  parameters: [
    { name: "title", type: "string", description: "Task title to complete", required: true },
  ],
  handler: async ({ title }) => {
    const lower = title.toLowerCase();
    setTasks(ts => ts.map(t => t.title.toLowerCase().includes(lower) ? { ...t, done: true } : t));
    return `Completed tasks matching "${title}"`;
  },
});

useCopilotAction({
  name: "clearCompleted",
  description: "Remove all completed tasks from the list",
  parameters: [],
  handler: async () => {
    setTasks(ts => ts.filter(t => !t.done));
    return "Cleared all completed tasks";
  },
});

// Generative UI via useCopilotAction render prop
// When the model calls "showWeather", render a weather card inline in the chat

useCopilotAction({
  name: "showWeather",
  description: "Display a weather card for a location",
  parameters: [
    { name: "location",  type: "string", required: true },
    { name: "temp",      type: "number", required: true },
    { name: "condition", type: "string", required: true },
    { name: "humidity",  type: "number", required: false },
  ],
  // render is called immediately when the model starts the tool call,
  // and re-called as streaming args fill in (status changes inProgress -> complete)
  render: ({ args, status }) => (
    <div className={`rounded-xl border p-4 my-2 transition-opacity ${
      status === "inProgress" ? "opacity-50 animate-pulse" : ""
    } border-sky-800 bg-sky-950`}>
      <p className="text-sky-300 font-semibold">{args.location ?? "…"}</p>
      <p className="text-4xl font-bold text-white mt-1">{args.temp != null ? `${args.temp}°C` : "…"}</p>
      <p className="text-sky-400 text-sm">{args.condition ?? ""}</p>
      {args.humidity != null && (
        <p className="text-sky-500 text-xs mt-1">Humidity: {args.humidity}%</p>
      )}
    </div>
  ),
  // handler is optional — if omitted the tool call is purely for UI display
  handler: async ({ location }) => {
    const data = await fetch(`/api/weather?location=${encodeURIComponent(location)}`).then(r => r.json());
    return data;
  },
});

// Custom-styled CopilotChat embedded in a panel (not a sidebar)
import { CopilotChat } from "@copilotkit/react-ui";

export function CopilotPanel() {
  return (
    <div className="h-full border-l border-slate-700">
      <CopilotChat
        instructions="You are a code review assistant. Focus on correctness and performance."
        labels={{
          title:   "Code Review Copilot",
          initial: "Paste code or describe what you need reviewed.",
        }}
        className="h-full"
      />
    </div>
  );
}

// TaskManager.test.tsx
import { render, screen, act } from "@testing-library/react";
import { CopilotKit }          from "@copilotkit/react-core";
import { TaskManager }          from "./TaskManager";

// Wrap in provider; point runtimeUrl at a test server or mock
function Wrapper({ children }: { children: React.ReactNode }) {
  return <CopilotKit runtimeUrl="http://localhost:8001/api/copilot">{children}</CopilotKit>;
}

test("renders empty state with no tasks", () => {
  render(<TaskManager />, { wrapper: Wrapper });
  expect(screen.queryAllByRole("listitem")).toHaveLength(0);
});

// For action testing, invoke the handler directly (no LLM needed):
test("addTask handler adds a task", async () => {
  let tasks: any[] = [];
  const setTasks = (fn: any) => { tasks = fn(tasks); };

  // Replicate the handler logic inline:
  const addTaskHandler = async ({ title, priority = "medium" }: any) => {
    setTasks((ts: any[]) => [...ts, { id: "1", title, done: false, priority }]);
    return `Added task: "${title}"`;
  };

  const result = await addTaskHandler({ title: "Write tests", priority: "high" });
  expect(result).toContain("Write tests");
  expect(tasks).toHaveLength(1);
  expect(tasks[0].priority).toBe("high");
});
